#include <iostream>
#include <iomanip>

int main() {
    double balance{1000.00};

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Current balance: $" << balance << std::endl;

    std::cout << "Enter amount: ";
    double amount{};
    std::cin >> amount;

    std::cout << "Enter type (D/W): ";
    char type{};
    std::cin >> type;

    if (type == 'D') {
        balance = balance + amount;
        std::cout << "Deposit of $" << amount << " processed. New balance: $" << balance << std::endl;
    } else if (type == 'W') {
        if (amount <= balance) {
            balance = balance - amount;
            std::cout << "Withdrawal of $" << amount << " processed. New balance: $" << balance << std::endl;
        } else {
            std::cout << "Error: Insufficient funds." << std::endl;
        }
    }

    return 0;
}

