        targetUnit = 'F';
    }
    else
    {
        result = (temperature - 32.0) * 5 / 9.0;
        targetUnit = 'C';
    }

    std::cout << std::fixed << std::setprecision(2)
              << result << ' ' << targetUnit << '\n';

    return 0;
}
